import React, { useState } from "react";
import "../styles/Purpose.css";
import { useNavigate } from "react-router-dom";

const options = [
  { id: 1, title: "Stress & Anxiety", emoji: "😰" },
  { id: 2, title: "Depression", emoji: "🌧️" },
  { id: 3, title: "Relationship Issues", emoji: "❤️‍🩹" },
  { id: 4, title: "Career / Study Pressure", emoji: "📚" },
  { id: 5, title: "Sleep Problems", emoji: "🌙" },
  { id: 6, title: "Just Need Someone to Talk", emoji: "💬" },
];

function Purpose() {
  const [selected, setSelected] = useState(null);
  const navigate = useNavigate();

  return (
    <div className="purpose-wrapper">
      <div className="purpose-card">
        <h2>What brings you here today?</h2>
        <p>This helps your AI therapist understand you better</p>

        <div className="purpose-grid">
          {options.map((item) => (
            <div
              key={item.id}
              className={`purpose-option ${
                selected === item.id ? "active" : ""
              }`}
              onClick={() => setSelected(item.id)}
            >
              <span>{item.emoji}</span>
              <p>{item.title}</p>
            </div>
          ))}
        </div>

        <button
          className="purpose-btn"
          disabled={!selected}
          onClick={() => navigate("/dashboard")}
        >
          Continue →
        </button>
      </div>
    </div>
  );
}

export default Purpose;
